package com.videodownload.app.ai

/**
 * AI 模型提供商
 */
enum class AIProvider(
    val displayName: String,
    val defaultBaseUrl: String,
    val defaultModel: String
) {
    OPENAI(
        displayName = "OpenAI (GPT-4)",
        defaultBaseUrl = "https://api.openai.com/v1",
        defaultModel = "gpt-4"
    ),
    ANTHROPIC(
        displayName = "Anthropic (Claude)",
        defaultBaseUrl = "https://api.anthropic.com/v1",
        defaultModel = "claude-3-5-sonnet-20241022"
    ),
    GOOGLE(
        displayName = "Google (Gemini)",
        defaultBaseUrl = "https://generativelanguage.googleapis.com/v1beta",
        defaultModel = "gemini-2.0-flash-exp"
    ),
    ALIBABA(
        displayName = "阿里云 (通义千问)",
        defaultBaseUrl = "https://dashscope.aliyuncs.com/compatible-mode/v1",
        defaultModel = "qwen-plus"
    ),
    BAIDU(
        displayName = "百度 (文心一言)",
        defaultBaseUrl = "https://aip.baidubce.com/rpc/2.0/ai_custom/v1",
        defaultModel = "ernie-4.0-8k"
    ),
    ZHIPU(
        displayName = "智谱 (GLM-4)",
        defaultBaseUrl = "https://open.bigmodel.cn/api/paas/v4",
        defaultModel = "glm-4-plus"
    );

    companion object {
        fun fromString(value: String): AIProvider {
            return entries.find { it.name == value } ?: OPENAI
        }
    }
}

/**
 * AI 模型配置
 */
data class AIModelConfig(
    val provider: AIProvider,
    val apiKey: String,
    val baseUrl: String = provider.defaultBaseUrl,
    val model: String = provider.defaultModel,
    val temperature: Float = 0.7f,
    val maxTokens: Int = 2000
)

package com.videodownload.app.ai

import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.*
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.RequestBody.Companion.toRequestBody
import org.json.JSONArray
import org.json.JSONObject
import java.util.concurrent.TimeUnit

/**
 * 统一的 AI 客户端
 * 支持多个 AI 提供商的统一调用接口
 */
class AIClient(private val config: AIModelConfig) {

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(60, TimeUnit.SECONDS)
        .build()

    /**
     * 发送聊天请求
     */
    suspend fun chat(prompt: String): String = withContext(Dispatchers.IO) {
        when (config.provider) {
            AIProvider.OPENAI -> chatOpenAI(prompt)
            AIProvider.ANTHROPIC -> chatAnthropic(prompt)
            AIProvider.GOOGLE -> chatGoogle(prompt)
            AIProvider.ALIBABA -> chatAlibaba(prompt)
            AIProvider.BAIDU -> chatBaidu(prompt)
            AIProvider.ZHIPU -> chatZhipu(prompt)
        }
    }

    /**
     * OpenAI 格式（兼容 OpenAI、阿里云、智谱）
     */
    private fun chatOpenAI(prompt: String): String {
        val requestBody = JSONObject().apply {
            put("model", config.model)
            put("messages", JSONArray().apply {
                put(JSONObject().apply {
                    put("role", "user")
                    put("content", prompt)
                })
            })
            put("temperature", config.temperature)
            put("max_tokens", config.maxTokens)
        }

        val request = Request.Builder()
            .url("${config.baseUrl}/chat/completions")
            .addHeader("Authorization", "Bearer ${config.apiKey}")
            .addHeader("Content-Type", "application/json")
            .post(requestBody.toString().toRequestBody("application/json".toMediaType()))
            .build()

        val response = client.newCall(request).execute()

        if (!response.isSuccessful) {
            throw Exception("API error: ${response.code} - ${response.body?.string()}")
        }

        val responseBody = response.body?.string()
            ?: throw Exception("Empty response")

        val jsonResponse = JSONObject(responseBody)
        return jsonResponse
            .getJSONArray("choices")
            .getJSONObject(0)
            .getJSONObject("message")
            .getString("content")
    }

    /**
     * Anthropic Claude 格式
     */
    private fun chatAnthropic(prompt: String): String {
        val requestBody = JSONObject().apply {
            put("model", config.model)
            put("messages", JSONArray().apply {
                put(JSONObject().apply {
                    put("role", "user")
                    put("content", prompt)
                })
            })
            put("max_tokens", config.maxTokens)
            put("temperature", config.temperature)
        }

        val request = Request.Builder()
            .url("${config.baseUrl}/messages")
            .addHeader("x-api-key", config.apiKey)
            .addHeader("anthropic-version", "2023-06-01")
            .addHeader("Content-Type", "application/json")
            .post(requestBody.toString().toRequestBody("application/json".toMediaType()))
            .build()

        val response = client.newCall(request).execute()

        if (!response.isSuccessful) {
            throw Exception("API error: ${response.code} - ${response.body?.string()}")
        }

        val responseBody = response.body?.string()
            ?: throw Exception("Empty response")

        val jsonResponse = JSONObject(responseBody)
        return jsonResponse
            .getJSONArray("content")
            .getJSONObject(0)
            .getString("text")
    }

    /**
     * Google Gemini 格式
     */
    private fun chatGoogle(prompt: String): String {
        val requestBody = JSONObject().apply {
            put("contents", JSONArray().apply {
                put(JSONObject().apply {
                    put("parts", JSONArray().apply {
                        put(JSONObject().apply {
                            put("text", prompt)
                        })
                    })
                })
            })
            put("generationConfig", JSONObject().apply {
                put("temperature", config.temperature)
                put("maxOutputTokens", config.maxTokens)
            })
        }

        val request = Request.Builder()
            .url("${config.baseUrl}/models/${config.model}:generateContent?key=${config.apiKey}")
            .addHeader("Content-Type", "application/json")
            .post(requestBody.toString().toRequestBody("application/json".toMediaType()))
            .build()

        val response = client.newCall(request).execute()

        if (!response.isSuccessful) {
            throw Exception("API error: ${response.code} - ${response.body?.string()}")
        }

        val responseBody = response.body?.string()
            ?: throw Exception("Empty response")

        val jsonResponse = JSONObject(responseBody)
        return jsonResponse
            .getJSONArray("candidates")
            .getJSONObject(0)
            .getJSONObject("content")
            .getJSONArray("parts")
            .getJSONObject(0)
            .getString("text")
    }

    /**
     * 阿里云通义千问（使用 OpenAI 兼容格式）
     */
    private fun chatAlibaba(prompt: String): String {
        return chatOpenAI(prompt)
    }

    /**
     * 百度文心一言
     */
    private fun chatBaidu(prompt: String): String {
        // 百度需要先获取 access_token，这里简化处理
        // 实际应该先调用 token 接口获取 access_token
        val requestBody = JSONObject().apply {
            put("messages", JSONArray().apply {
                put(JSONObject().apply {
                    put("role", "user")
                    put("content", prompt)
                })
            })
            put("temperature", config.temperature)
            put("max_output_tokens", config.maxTokens)
        }

        val request = Request.Builder()
            .url("${config.baseUrl}/wenxinworkshop/chat/completions?access_token=${config.apiKey}")
            .addHeader("Content-Type", "application/json")
            .post(requestBody.toString().toRequestBody("application/json".toMediaType()))
            .build()

        val response = client.newCall(request).execute()

        if (!response.isSuccessful) {
            throw Exception("API error: ${response.code} - ${response.body?.string()}")
        }

        val responseBody = response.body?.string()
            ?: throw Exception("Empty response")

        val jsonResponse = JSONObject(responseBody)
        return jsonResponse.getString("result")
    }

    /**
     * 智谱 GLM（使用 OpenAI 兼容格式）
     */
    private fun chatZhipu(prompt: String): String {
        return chatOpenAI(prompt)
    }

    /**
     * 测试连接
     */
    suspend fun testConnection(): TestResult = withContext(Dispatchers.IO) {
        try {
            val response = chat("Hello")
            TestResult(success = true, message = "连接成功")
        } catch (e: Exception) {
            TestResult(success = false, message = "连接失败: ${e.message}")
        }
    }
}

/**
 * 测试结果
 */
data class TestResult(
    val success: Boolean,
    val message: String
)

