package com.videodownload.app.ui.settings

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.videodownload.app.ai.AIClient
import com.videodownload.app.ai.AIModelConfig
import com.videodownload.app.ai.AIProvider
import com.videodownload.app.repository.TranscriptionRepository
import com.videodownload.app.utils.PreferenceManager
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import java.io.File

/**
 * 设置 ViewModel
 */
class SettingsViewModel(application: Application) : AndroidViewModel(application) {

    private val preferenceManager = PreferenceManager(application)
    private val repository = TranscriptionRepository(application)

    private val _settings = MutableStateFlow(loadSettings())
    val settings: StateFlow<AppSettings> = _settings.asStateFlow()

    private val _uiState = MutableStateFlow<SettingsUiState>(SettingsUiState.Idle)
    val uiState: StateFlow<SettingsUiState> = _uiState.asStateFlow()

    private fun loadSettings(): AppSettings {
        val currentProvider = preferenceManager.getAIProvider()
        return AppSettings(
            // 旧的 Groq 配置
            groqApiKey = preferenceManager.getGroqApiKey(),
            defaultEngine = preferenceManager.getDefaultEngine(),
            aiAssistantEnabled = preferenceManager.isAIAssistantEnabled(),
            autoTranscribeEnabled = preferenceManager.isAutoTranscribeEnabled(),
            downloadPath = preferenceManager.getDownloadPath(),
            // 新的 AI 模型配置
            aiProvider = currentProvider,
            aiApiKey = preferenceManager.getAIApiKey(currentProvider),
            aiBaseUrl = preferenceManager.getAIBaseUrl(currentProvider),
            aiModel = preferenceManager.getAIModel(currentProvider)
        )
    }

    // ==================== AI 模型配置 ====================

    /**
     * 更新 AI 提供商
     */
    fun updateAIProvider(provider: AIProvider) {
        preferenceManager.setAIProvider(provider)
        _settings.value = _settings.value.copy(
            aiProvider = provider,
            aiApiKey = preferenceManager.getAIApiKey(provider),
            aiBaseUrl = preferenceManager.getAIBaseUrl(provider),
            aiModel = preferenceManager.getAIModel(provider)
        )
    }

    /**
     * 更新 API Key
     */
    fun updateAIApiKey(apiKey: String) {
        val provider = _settings.value.aiProvider
        preferenceManager.setAIApiKey(provider, apiKey)
        _settings.value = _settings.value.copy(aiApiKey = apiKey)
    }

    /**
     * 更新 Base URL
     */
    fun updateAIBaseUrl(baseUrl: String) {
        val provider = _settings.value.aiProvider
        preferenceManager.setAIBaseUrl(provider, baseUrl)
        _settings.value = _settings.value.copy(aiBaseUrl = baseUrl)
    }

    /**
     * 更新模型
     */
    fun updateAIModel(model: String) {
        val provider = _settings.value.aiProvider
        preferenceManager.setAIModel(provider, model)
        _settings.value = _settings.value.copy(aiModel = model)
    }

    /**
     * 重置为默认配置
     */
    fun resetToDefault() {
        val provider = _settings.value.aiProvider
        preferenceManager.setAIBaseUrl(provider, provider.defaultBaseUrl)
        preferenceManager.setAIModel(provider, provider.defaultModel)
        _settings.value = _settings.value.copy(
            aiBaseUrl = provider.defaultBaseUrl,
            aiModel = provider.defaultModel
        )
    }

    /**
     * 测试 AI 连接
     */
    fun testAIConnection() {
        viewModelScope.launch {
            _uiState.value = SettingsUiState.Testing

            try {
                val config = AIModelConfig(
                    provider = _settings.value.aiProvider,
                    apiKey = _settings.value.aiApiKey ?: "",
                    baseUrl = _settings.value.aiBaseUrl,
                    model = _settings.value.aiModel
                )

                val client = AIClient(config)
                val result = client.testConnection()

                _uiState.value = if (result.success) {
                    SettingsUiState.TestSuccess(result.message)
                } else {
                    SettingsUiState.TestFailed(result.message)
                }
            } catch (e: Exception) {
                _uiState.value = SettingsUiState.TestFailed("测试失败: ${e.message}")
            }
        }
    }

    // ==================== 旧的配置方法（保留兼容性）====================

