/**
 * AI 模型配置
 */
@OptIn(ExperimentalMaterial3Api::class)
@Composable
private fun AIModelConfigSection(
    settings: AppSettings,
    uiState: SettingsUiState,
    onProviderChange: (AIProvider) -> Unit,
    onApiKeyChange: (String) -> Unit,
    onBaseUrlChange: (String) -> Unit,
    onModelChange: (String) -> Unit,
    onResetToDefault: () -> Unit,
    onTestConnection: () -> Unit
) {
    var apiKey by remember(settings.aiApiKey) { mutableStateOf(settings.aiApiKey ?: "") }
    var baseUrl by remember(settings.aiBaseUrl) { mutableStateOf(settings.aiBaseUrl) }
    var model by remember(settings.aiModel) { mutableStateOf(settings.aiModel) }
    var showApiKey by remember { mutableStateOf(false) }
    var showProviderMenu by remember { mutableStateOf(false) }

    Card(
        modifier = Modifier.fillMaxWidth()
    ) {
        Column(
            modifier = Modifier.padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            Text(
                text = "AI 模型配置",
                style = MaterialTheme.typography.titleMedium
            )

            // 提供商选择
            ExposedDropdownMenuBox(
                expanded = showProviderMenu,
                onExpandedChange = { showProviderMenu = it }
            ) {
                OutlinedTextField(
                    value = settings.aiProvider.displayName,
                    onValueChange = {},
                    readOnly = true,
                    label = { Text("AI 提供商") },
                    trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = showProviderMenu) },
                    modifier = Modifier
                        .fillMaxWidth()
                        .menuAnchor()
                )

                ExposedDropdownMenu(
                    expanded = showProviderMenu,
                    onDismissRequest = { showProviderMenu = false }
                ) {
                    AIProvider.entries.forEach { provider ->
                        DropdownMenuItem(
                            text = { Text(provider.displayName) },
                            onClick = {
                                onProviderChange(provider)
                                showProviderMenu = false
                            }
                        )
                    }
                }
            }

            // API Key 输入
            OutlinedTextField(
                value = apiKey,
                onValueChange = {
                    apiKey = it
                    onApiKeyChange(it)
                },
                label = { Text("API Key") },
                placeholder = { Text(getApiKeyPlaceholder(settings.aiProvider)) },
                modifier = Modifier.fillMaxWidth(),
                visualTransformation = if (showApiKey) {
                    VisualTransformation.None
                } else {
                    PasswordVisualTransformation()
                },
                trailingIcon = {
                    IconButton(onClick = { showApiKey = !showApiKey }) {
                        Icon(
                            if (showApiKey) Icons.Default.Visibility else Icons.Default.VisibilityOff,
                            contentDescription = if (showApiKey) "隐藏" else "显示"
                        )
                    }
                },
                supportingText = {
                    Text(getApiKeyHint(settings.aiProvider))
                }
            )

            // Base URL 输入
            OutlinedTextField(
                value = baseUrl,
                onValueChange = {
                    baseUrl = it
                    onBaseUrlChange(it)
                },
                label = { Text("Base URL") },
                placeholder = { Text(settings.aiProvider.defaultBaseUrl) },
                modifier = Modifier.fillMaxWidth(),
                supportingText = {
                    Text("自定义 API 端点（可选）")
                }
            )

            // 模型输入
            OutlinedTextField(
                value = model,
                onValueChange = {
                    model = it
                    onModelChange(it)
                },
                label = { Text("模型") },
                placeholder = { Text(settings.aiProvider.defaultModel) },
                modifier = Modifier.fillMaxWidth(),
                supportingText = {
                    Text("默认: ${settings.aiProvider.defaultModel}")
                }
            )

            // 操作按钮
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                OutlinedButton(
                    onClick = onResetToDefault,
                    modifier = Modifier.weight(1f)
                ) {
                    Icon(Icons.Default.Refresh, contentDescription = null)
                    Spacer(modifier = Modifier.width(4.dp))
                    Text("重置")
                }

                Button(
                    onClick = onTestConnection,
                    modifier = Modifier.weight(1f),
                    enabled = apiKey.isNotBlank() && uiState !is SettingsUiState.Testing
                ) {
                    if (uiState is SettingsUiState.Testing) {
                        CircularProgressIndicator(
                            modifier = Modifier.size(16.dp),
                            strokeWidth = 2.dp,
                            color = MaterialTheme.colorScheme.onPrimary
                        )
                        Spacer(modifier = Modifier.width(8.dp))
                        Text("测试中...")
                    } else {
                        Icon(Icons.Default.CheckCircle, contentDescription = null)
                        Spacer(modifier = Modifier.width(4.dp))
                        Text("测试")
                    }
                }
            }

            // 测试结果
            when (uiState) {
                is SettingsUiState.TestSuccess -> {
                    Card(
                        colors = CardDefaults.cardColors(
                            containerColor = MaterialTheme.colorScheme.primaryContainer
                        )
                    ) {
                        Row(
                            modifier = Modifier.padding(12.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Icon(
                                Icons.Default.CheckCircle,
                                contentDescription = null,
                                tint = MaterialTheme.colorScheme.primary
                            )
                            Spacer(modifier = Modifier.width(8.dp))
                            Text(
                                text = uiState.message,
                                style = MaterialTheme.typography.bodyMedium
                            )
                        }
                    }
                }

                is SettingsUiState.TestFailed -> {
                    Card(
                        colors = CardDefaults.cardColors(
                            containerColor = MaterialTheme.colorScheme.errorContainer
                        )
                    ) {
                        Row(
                            modifier = Modifier.padding(12.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Icon(
                                Icons.Default.Error,
                                contentDescription = null,
                                tint = MaterialTheme.colorScheme.error
                            )
                            Spacer(modifier = Modifier.width(8.dp))
                            Text(
                                text = uiState.message,
                                style = MaterialTheme.typography.bodyMedium
                            )
                        }
                    }
                }

                else -> {}
            }
        }
    }
}

/**
 * 获取 API Key 占位符
 */
private fun getApiKeyPlaceholder(provider: AIProvider): String {
    return when (provider) {
        AIProvider.OPENAI -> "sk-..."
        AIProvider.ANTHROPIC -> "sk-ant-..."
        AIProvider.GOOGLE -> "AIza..."
        AIProvider.ALIBABA -> "sk-..."
        AIProvider.BAIDU -> "access_token"
        AIProvider.ZHIPU -> "..."
    }
}

/**
 * 获取 API Key 提示
 */
private fun getApiKeyHint(provider: AIProvider): String {
    return when (provider) {
        AIProvider.OPENAI -> "获取: https://platform.openai.com/api-keys"
        AIProvider.ANTHROPIC -> "获取: https://console.anthropic.com/"
        AIProvider.GOOGLE -> "获取: https://aistudio.google.com/app/apikey"
        AIProvider.ALIBABA -> "获取: https://dashscope.console.aliyun.com/"
        AIProvider.BAIDU -> "获取: https://console.bce.baidu.com/qianfan/"
        AIProvider.ZHIPU -> "获取: https://open.bigmodel.cn/"
    }
}

