package com.videodownload.app.ai

import kotlinx.coroutines.runBlocking
import org.junit.Test
import org.junit.Assert.*

/**
 * AI 客户端测试
 */
class AIClientTest {

    /**
     * 测试 OpenAI 格式
     */
    @Test
    fun testOpenAIFormat() {
        val config = AIModelConfig(
            provider = AIProvider.OPENAI,
            apiKey = "test_key",
            baseUrl = "https://api.openai.com/v1",
            model = "gpt-4"
        )

        val client = AIClient(config)
        assertNotNull(client)
    }

    /**
     * 测试 Anthropic 格式
     */
    @Test
    fun testAnthropicFormat() {
        val config = AIModelConfig(
            provider = AIProvider.ANTHROPIC,
            apiKey = "test_key",
            baseUrl = "https://api.anthropic.com/v1",
            model = "claude-3-5-sonnet-20241022"
        )

        val client = AIClient(config)
        assertNotNull(client)
    }

    /**
     * 测试 Google 格式
     */
    @Test
    fun testGoogleFormat() {
        val config = AIModelConfig(
            provider = AIProvider.GOOGLE,
            apiKey = "test_key",
            baseUrl = "https://generativelanguage.googleapis.com/v1beta",
            model = "gemini-2.0-flash-exp"
        )

        val client = AIClient(config)
        assertNotNull(client)
    }

    /**
     * 测试阿里云格式
     */
    @Test
    fun testAlibabaFormat() {
        val config = AIModelConfig(
            provider = AIProvider.ALIBABA,
            apiKey = "test_key",
            baseUrl = "https://dashscope.aliyuncs.com/compatible-mode/v1",
            model = "qwen-plus"
        )

        val client = AIClient(config)
        assertNotNull(client)
    }

    /**
     * 测试百度格式
     */
    @Test
    fun testBaiduFormat() {
        val config = AIModelConfig(
            provider = AIProvider.BAIDU,
            apiKey = "test_key",
            baseUrl = "https://aip.baidubce.com/rpc/2.0/ai_custom/v1",
            model = "ernie-4.0-8k"
        )

        val client = AIClient(config)
        assertNotNull(client)
    }

    /**
     * 测试智谱格式
     */
    @Test
    fun testZhipuFormat() {
        val config = AIModelConfig(
            provider = AIProvider.ZHIPU,
            apiKey = "test_key",
            baseUrl = "https://open.bigmodel.cn/api/paas/v4",
            model = "glm-4-plus"
        )

        val client = AIClient(config)
        assertNotNull(client)
    }

    /**
     * 测试提供商枚举
     */
    @Test
    fun testProviderEnum() {
        assertEquals(6, AIProvider.entries.size)

        assertEquals("OpenAI (GPT-4)", AIProvider.OPENAI.displayName)
        assertEquals("Anthropic (Claude)", AIProvider.ANTHROPIC.displayName)
        assertEquals("Google (Gemini)", AIProvider.GOOGLE.displayName)
        assertEquals("阿里云 (通义千问)", AIProvider.ALIBABA.displayName)
        assertEquals("百度 (文心一言)", AIProvider.BAIDU.displayName)
        assertEquals("智谱 (GLM-4)", AIProvider.ZHIPU.displayName)
    }

    /**
     * 测试提供商转换
     */
    @Test
    fun testProviderFromString() {
        assertEquals(AIProvider.OPENAI, AIProvider.fromString("OPENAI"))
        assertEquals(AIProvider.ANTHROPIC, AIProvider.fromString("ANTHROPIC"))
        assertEquals(AIProvider.GOOGLE, AIProvider.fromString("GOOGLE"))
        assertEquals(AIProvider.ALIBABA, AIProvider.fromString("ALIBABA"))
        assertEquals(AIProvider.BAIDU, AIProvider.fromString("BAIDU"))
        assertEquals(AIProvider.ZHIPU, AIProvider.fromString("ZHIPU"))

        // 测试无效值
        assertEquals(AIProvider.OPENAI, AIProvider.fromString("INVALID"))
    }

    /**
     * 测试模型配置
     */
    @Test
    fun testModelConfig() {
        val config = AIModelConfig(
            provider = AIProvider.OPENAI,
            apiKey = "test_key",
            baseUrl = "https://custom.api.com",
            model = "custom-model",
            temperature = 0.5f,
            maxTokens = 1000
        )

        assertEquals(AIProvider.OPENAI, config.provider)
        assertEquals("test_key", config.apiKey)
        assertEquals("https://custom.api.com", config.baseUrl)
        assertEquals("custom-model", config.model)
        assertEquals(0.5f, config.temperature)
        assertEquals(1000, config.maxTokens)
    }

    /**
     * 测试默认配置
     */
    @Test
    fun testDefaultConfig() {
        val config = AIModelConfig(
            provider = AIProvider.OPENAI,
            apiKey = "test_key"
        )

        assertEquals(AIProvider.OPENAI.defaultBaseUrl, config.baseUrl)
        assertEquals(AIProvider.OPENAI.defaultModel, config.model)
        assertEquals(0.7f, config.temperature)
        assertEquals(2000, config.maxTokens)
    }

    /**
     * 测试模型推荐
     */
    @Test
    fun testModelRecommendations() {
        // 测试查词场景
        val wordLookupProviders = AIModelRecommendations.getRecommendedProvider(AIScenario.WORD_LOOKUP)
        assertTrue(wordLookupProviders.contains(AIProvider.ALIBABA))

        // 测试修复转录场景
        val fixProviders = AIModelRecommendations.getRecommendedProvider(AIScenario.FIX_TRANSCRIPTION)
        assertTrue(fixProviders.contains(AIProvider.OPENAI))

        // 测试学习笔记场景
        val notesProviders = AIModelRecommendations.getRecommendedProvider(AIScenario.STUDY_NOTES)
        assertTrue(notesProviders.contains(AIProvider.ANTHROPIC))

        // 测试词汇分析场景
        val vocabProviders = AIModelRecommendations.getRecommendedProvider(AIScenario.VOCABULARY_ANALYSIS)
        assertTrue(vocabProviders.contains(AIProvider.GOOGLE))
    }

    /**
     * 测试用户偏好推荐
     */
    @Test
    fun testUserPreferenceRecommendation() {
        // 优先中文和成本
        val pref1 = UserPreference(prioritizeChinese = true, prioritizeCost = true)
        assertEquals(AIProvider.ZHIPU, AIModelRecommendations.recommendByPreference(pref1))

        // 优先中文和速度
        val pref2 = UserPreference(prioritizeChinese = true, prioritizeSpeed = true)
        assertEquals(AIProvider.ALIBABA, AIModelRecommendations.recommendByPreference(pref2))

        // 优先准确度和长文本
        val pref3 = UserPreference(prioritizeAccuracy = true, prioritizeLongContext = true)
        assertEquals(AIProvider.ANTHROPIC, AIModelRecommendations.recommendByPreference(pref3))

        // 优先成本
        val pref4 = UserPreference(prioritizeCost = true)
        assertEquals(AIProvider.GOOGLE, AIModelRecommendations.recommendByPreference(pref4))
    }

    /**
     * 测试模型特性
     */
    @Test
    fun testModelCharacteristics() {
        val openaiChars = AIModelRecommendations.getModelCharacteristics(AIProvider.OPENAI)
        assertEquals(5, openaiChars.accuracy)
        assertTrue(openaiChars.speed >= 1 && openaiChars.speed <= 5)

        val zhipuChars = AIModelRecommendations.getModelCharacteristics(AIProvider.ZHIPU)
        assertEquals(5, zhipuChars.chineseSupport)
        assertEquals(5, zhipuChars.costEfficiency)
    }

    /**
     * 测试提供商优势
     */
    @Test
    fun testProviderAdvantages() {
        val openaiAdvantages = AIModelRecommendations.getProviderAdvantages(AIProvider.OPENAI)
        assertTrue(openaiAdvantages.isNotEmpty())
        assertTrue(openaiAdvantages.any { it.contains("通用能力") })

        val alibabaAdvantages = AIModelRecommendations.getProviderAdvantages(AIProvider.ALIBABA)
        assertTrue(alibabaAdvantages.any { it.contains("中文") })
    }

    /**
     * 测试提供商使用场景
     */
    @Test
    fun testProviderUseCases() {
        val anthropicUseCases = AIModelRecommendations.getProviderUseCases(AIProvider.ANTHROPIC)
        assertTrue(anthropicUseCases.isNotEmpty())
        assertTrue(anthropicUseCases.any { it.contains("长文档") })

        val googleUseCases = AIModelRecommendations.getProviderUseCases(AIProvider.GOOGLE)
        assertTrue(googleUseCases.any { it.contains("多模态") })
    }
}
